import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '@/lib/api';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Select } from '@/components/ui/select';

interface User {
  id: string;
  email: string;
  firstName: string;
  lastName: string;
  role: 'admin' | 'seller' | 'customer';
  isBlocked: boolean;
  createdAt: string;
}

interface UsersResponse {
  users: User[];
  total: number;
  page: number;
  totalPages: number;
}

const UserManagement = () => {
  const queryClient = useQueryClient();
  const [page, setPage] = useState(1);
  const [search, setSearch] = useState('');
  const [roleFilter, setRoleFilter] = useState('');
  const limit = 10;

  // Requête pour récupérer les utilisateurs
  const { data, isLoading, isError } = useQuery<UsersResponse>({
    queryKey: ['admin-users', page, search, roleFilter],
    queryFn: () => api.get('/admin/users', { params: { page, limit, search: search || undefined, role: roleFilter || undefined } }),
    keepPreviousData: true,
  });

  // Mutation pour bloquer/débloquer
  const toggleBlockMutation = useMutation({
    mutationFn: ({ userId, isBlocked }: { userId: string; isBlocked: boolean }) =>
      api.patch(`/admin/users/${userId}/block`, { isBlocked }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-users'] });
      toast.success('Statut du compte mis à jour');
    },
    onError: () => toast.error('Erreur lors de la mise à jour'),
  });

  // Mutation pour changer le rôle
  const changeRoleMutation = useMutation({
    mutationFn: ({ userId, role }: { userId: string; role: User['role'] }) =>
      api.patch(`/admin/users/${userId}/role`, { role }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-users'] });
      toast.success('Rôle modifié avec succès');
    },
  });

  if (isLoading) return <div className="p-8 text-center">Chargement des utilisateurs...</div>;
  if (isError) return <div className="p-8 text-center text-red-500">Erreur lors du chargement</div>;

  return (
    <div className="p-6">
      <h2 className="text-2xl font-bold mb-4">Gestion des utilisateurs</h2>

      {/* Barre de filtres */}
      <div className="flex flex-col md:flex-row gap-4 mb-6">
        <Input
          placeholder="Rechercher par nom ou email..."
          value={search}
          onChange={(e) => { setSearch(e.target.value); setPage(1); }}
          className="md:w-80"
        />
        <Select value={roleFilter} onValueChange={(val) => { setRoleFilter(val); setPage(1); }}>
          <option value="">Tous les rôles</option>
          <option value="admin">Administrateurs</option>
          <option value="seller">Vendeurs</option>
          <option value="customer">Clients</option>
        </Select>
      </div>

      {/* Tableau */}
      <div className="overflow-x-auto">
        <table className="w-full border-collapse">
          <thead className="bg-gray-100">
            <tr><th className="p-3 text-left">Nom</th><th>Email</th><th>Rôle</th><th>Statut</th><th>Date inscription</th><th>Actions</th></tr>
          </thead>
          <tbody>
            {data?.users.map((user) => (
              <tr key={user.id} className="border-b hover:bg-gray-50">
                <td className="p-3">{user.firstName} {user.lastName}</td>
                <td className="p-3">{user.email}</td>
                <td className="p-3">
                  <Select
                    value={user.role}
                    onValueChange={(role) => changeRoleMutation.mutate({ userId: user.id, role: role as User['role'] })}
                  >
                    <option value="customer">Client</option>
                    <option value="seller">Vendeur</option>
                    <option value="admin">Admin</option>
                  </Select>
                </td>
                <td className="p-3">
                  <span className={`px-2 py-1 rounded-full text-xs ${user.isBlocked ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-700'}`}>
                    {user.isBlocked ? 'Bloqué' : 'Actif'}
                  </span>
                </td>
                <td className="p-3">{new Date(user.createdAt).toLocaleDateString('fr-FR')}</td>
                <td className="p-3">
                  <Button
                    variant={user.isBlocked ? 'outline' : 'destructive'}
                    size="sm"
                    onClick={() => toggleBlockMutation.mutate({ userId: user.id, isBlocked: !user.isBlocked })}
                  >
                    {user.isBlocked ? 'Débloquer' : 'Bloquer'}
                  </Button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      <div className="flex justify-between items-center mt-6">
        <span className="text-sm text-gray-500">
          Page {data?.page} sur {data?.totalPages}
        </span>
        <div className="flex gap-2">
          <Button onClick={() => setPage(p => Math.max(1, p-1))} disabled={page === 1}>
            Précédent
          </Button>
          <Button onClick={() => setPage(p => Math.min(data?.totalPages || 1, p+1))} disabled={page === data?.totalPages}>
            Suivant
          </Button>
        </div>
      </div>
    </div>
  );
};

export default UserManagement;
