import { useState, useCallback, useRef } from 'react';

const UserManagement = () => {
  const [searchInput, setSearchInput] = useState('');
  const [debouncedSearch, setDebouncedSearch] = useState('');
  const timerRef = useRef<NodeJS.Timeout>();

  const handleSearchChange = useCallback((value: string) => {
    setSearchInput(value);

    // Annuler le timer précédent
    if (timerRef.current) {
      clearTimeout(timerRef.current);
    }

    // Démarrer un nouveau timer
    timerRef.current = setTimeout(() => {
      setDebouncedSearch(value);
    }, 300);
  }, []);

  // Utiliser debouncedSearch dans la queryKey
  const { data } = useQuery({
    queryKey: ['admin-users', page, debouncedSearch, roleFilter],
    queryFn: () => api.get('/admin/users', { params: { page, limit, search: debouncedSearch || undefined } }),
    keepPreviousData: true,
  });

  return (
    <Input
      value={searchInput}
      onChange={(e) => handleSearchChange(e.target.value)}
      placeholder="Rechercher..."
    />
  );
};
```

**Explication** : Sans debounce, taper 'Jean-Philippe Martin' (18 caractères) déclencherait 18 appels API inutiles. Avec debounce, un seul appel est fait 300ms après la dernière frappe, réduisant la charge serveur et évitant les erreurs de 'race conditions' où les réponses arrivent dans un ordre différent de la saisie.

