import { useAuthStore } from '@/stores/authStore';

const toggleBlockMutation = useMutation({
  mutationFn: ({ userId, isBlocked }: { userId: string; isBlocked: boolean }) =>
    api.patch(`/admin/users/${userId}/block`, { isBlocked }),
  onSuccess: () => {
    queryClient.invalidateQueries({ queryKey: ['admin-users'] });
    toast.success('Statut du compte mis à jour');
  },
  onError: (error: any) => {
    if (error.response?.status === 409) {
      toast.error(error.response?.data?.message || 'Action non autorisée sur cet utilisateur');
    } else if (error.response?.status === 403) {
      toast.error('Vous ne pouvez pas bloquer votre propre compte');
    } else {
      toast.error('Erreur lors de la mise à jour du statut');
    }
  },
});

