const exportToCSV = (users: User[], filename: string) => {
  // Définition des colonnes
  const headers = ['ID', 'Prénom', 'Nom', 'Email', 'Rôle', 'Bloqué', 'Date inscription'];

  // Transformation des données
  const rows = users.map(user => [
    user.id,
    user.firstName,
    user.lastName,
    user.email,
    user.role,
    user.isBlocked ? 'Oui' : 'Non',
    new Date(user.createdAt).toLocaleDateString('fr-FR')
  ]);

  // Construction du contenu CSV
  const csvContent = [
    headers.join(';'),
    ...rows.map(row => row.map(cell => `"${cell}"`).join(';'))
  ].join('\n');

  // Ajout du BOM pour UTF-8 (compatibilité accents)
  const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.setAttribute('download', filename);
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(url);
};

// Récupération de tous les utilisateurs pour l'export
const exportAllFilteredUsers = async () => {
  // Option 1 : L'API peut avoir un endpoint spécifique /admin/users/export?search=...&role=...
  // Option 2 : Récupérer toutes les pages en boucle
  let allUsers: User[] = [];
  let currentPage = 1;
  let totalPages = 1;

  do {
    const response = await api.get('/admin/users', {
      params: { page: currentPage, limit: 100, search, role: roleFilter }
    });
    allUsers = [...allUsers, ...response.data.users];
    totalPages = response.data.totalPages;
    currentPage++;
  } while (currentPage <= totalPages);

  exportToCSV(allUsers, `utilisateurs_${new Date().toISOString().slice(0,19)}.csv`);
};
```

**Recommandation** : Pour un grand nombre d'utilisateurs, il est préférable que le backend génère directement le CSV et fournisse une URL de téléchargement, évitant ainsi de charger des milliers d'utilisateurs en mémoire côté frontend.
